import { get, writable } from "svelte/store";
import { multiDeleteNodes, Node, nodesSetToArray } from "./nodes.svelte";
import { StyledComp } from "../util/classes/StyledComp";
import type { IJsonable, NodeJson, TabJson } from "../util/interfaces";
import { Camera, currentCamera } from "./cameras.svelte";
import { tick } from "svelte";
import { userConfig } from "../data/userConfig";
import { CircularArray } from "../util/classes/CircularArray";
import { getLast } from "../util/util.svelte";
import { leftSidebarOpen } from "./app.svelte";

export const tabs = writable<Tab[]>([])
export const currentTab = writable<Tab>(null!)

export function resetTabs()
{
    tabs.set([])
    currentTab.set(null!)
}

export class Tab extends StyledComp implements IJsonable
{
    public camera: Camera
    public name: string
    public readonly nodes: Node[] = []
    public selected = false

    constructor(public rootNode: Node)
    {
        super()

        this.name = this.rootNode?.text ?? "New Tab"

        this.camera = new Camera
        (
            0,
            0,
            1,
        )

        tabs.update(tabs => [...tabs, this])

        Tab.update()
    }

    getFirstSelectedNode(): Node
    {
        for(const node of this.selectedNodes)
        {
            if(!node.alive)
            {
                continue
            }

            return node
        }

        return null!
    }

    setRootNode(rootNode: Node, centerCamera: boolean = true)
    {
        this.rootNode = rootNode
        this.name = rootNode.text

        if(centerCamera)
        {
            this.camera.x = (window.innerWidth - this.rootNode.size.x) / 2
            this.camera.goalX = this.camera.x

            this.camera.y = (window.innerHeight - this.rootNode.size.y) / 2
            this.camera.goalY = this.camera.y
        }
    }

    onMouseDown(e: MouseEvent)
    {
        if(!this.selected)
        {
            leftSidebarOpen.set(true)
            leftSidebarOpen.set(false)
            this.select()
        }
    }

    update(nextTick: boolean = false, animate: boolean = this.shouldAnimate())
    {
        if(nextTick)
        {
            tick().then(() => this.update(false))
            return
        }

        if(this.rootNode == null)
        {
            return
        }

        this.rootNode.updateChildrenRecursive(animate)
        Tab.update()
    }

    async updateNextTick()
    {
        await tick()
        this.update(false)
    }

    toJson(): TabJson
    {
        return {
            camera: this.camera.toJson(),
            rootNode: this.rootNode.toJson(),
        }
    }

    deselect()
    {
        this.selected = false
    }

    async select()
    {
        const previousTab = get(currentTab)

        if(previousTab != null)
        {
            if(previousTab != this)
            {
                previousTab.deselect()
                currentTab.set(null!)
            }
        }

        await tick()
        this.selected = true

        this.rootNode.animateOpacityBirthRecursive()

        currentTab.set(this)
        currentCamera.set(this.camera)

        await this.updateNextTick()
    }
    
    get dynamicIndex()
    {
        return get(tabs).indexOf(this)
    }

    static fromJson(tabJson?: TabJson): Tab
    {
        if(tabJson == null)
        {
            return this.fromNodeJson()
        }

        const tab = this.fromNodeJson(tabJson.rootNode)

        tab.camera = Camera.fromJson(tabJson.camera)

        return tab
    }

    static fromNodeJson(rootNodeJson?: NodeJson): Tab
    {
        let rootNode: Node

        const tab = new Tab(null!)

        if(rootNodeJson == null)
        {
            rootNode = new Node(tab, null!, "New Tab")
        }
        else
        {
            rootNode = Node.fromJson(tab, rootNodeJson!)
        }

        tab.setRootNode(rootNode)

        return tab
    }

    static update(nextTick: boolean = false)
    {
        if(nextTick)
        {
            tick().then(() => this.update(false))
            return
        }

        currentTab.update(tab => tab)
        tabs.update(tabs => tabs)
    }

    static async updateNextTick()
    {
        await tick()
        this.update()
    }

    //#region selection
    readonly selectedNodes: Set<Node> = new Set()
    lastSelectedNodes: CircularArray<Node> = new CircularArray<Node>(1000)
    lastSelectedNode: Node = null!

    getLastSelectedAliveNode()
    {
        for(let i = 0; i < this.lastSelectedNodes.length; i++)
        {
            const node = this.lastSelectedNodes.getFromNewToOld(i)!

            if(node.alive)
            {
                return node
            }

            this.lastSelectedNodes.pop()
        }

        return null!
    }

    createChildForNode(parent: Node = this.getFirstSelectedNode(), belowNode?: Node)
    {
        if(parent != null)
        {
            const childNode = parent.createChild(belowNode)

            this.deselectNodes()
            this.selectNodes(childNode, true)

            childNode.focus()
        }
    }

    deleteSelectedNodes()
    {
        if(this.selectedNodes.size > 0)
        {
            const lastNode = getLast([...this.selectedNodes])
            multiDeleteNodes(this.selectedNodes)

            this.deselectNodes()
            const nextInKin = lastNode.getNextInKin()

            console.log(nextInKin)

            if(nextInKin != null)
            {
                this.selectNodes(nextInKin, false)
            }
        }
    }

    forEachSelectedNode(callback: (node: Node) => void)
    {
        this.selectedNodes.forEach(callback)
    }

    selectNodes(nodes: Iterable<Node> | Node, clearOld: boolean)
    {
        if(clearOld)
        {
            this.deselectNodes()
        }

        if(nodes == null)
        {
            return
        }

        if(nodes instanceof Node)
        {
            nodes.setSelected(true)
            this.selectedNodes.add(nodes)
            this.lastSelectedNodes.push(nodes)
            this.lastSelectedNode = nodes
        }
        else
        {
            for(const node of nodes)
            {
                this.selectNodes(node, false)
            }
        }
    }

    deselectNodes(nodes: Iterable<Node> | Node = undefined!)
    {
        if(nodes == null)
        {
            this.deselectNodes(this.selectedNodes)
        }
        else
        {
            if(nodes instanceof Node)
            {
                nodes.setSelected(false)
                this.selectedNodes.delete(nodes)
            }
            else
            {

                for(const node of nodes)
                {
                    this.deselectNodes(node)
                }
            }
        }
    }

    selectLastSelectedAliveNodeIfNoneSelected(): Node | null
    {
        if(this.selectedNodes.size != 0)
        {
            return null
        }

        const lastSelectedNode = this.getLastSelectedAliveNode()

        if(lastSelectedNode == null)
        {
            return null
        }

        this.selectNodes(lastSelectedNode, false)

        return lastSelectedNode
    }
    //#endregion selection

    shouldAnimate()
    {
        if(!userConfig.get("ANIMATED"))
        {
            return false
        }

        if(200 < this.nodes.length)
        {
            return false
        }

        const selectedTab = get(currentTab)

        if(selectedTab != this)
        {
            return false
        }

        return true
    }

    getSelectedNodesAsArray(): Node[]
    {
        return nodesSetToArray(this.selectedNodes)
    }
}

export let tabIndexFocusedNode: Node | null = null

export function setTabIndexFocusedNode(node?: Node | null)
{
    tabIndexFocusedNode = node ?? null
}