export namespace Node
{
    export function fromJson(tab: Tab, json: NodeJson): Node
    {
        if(json == null)
        {
            return new Node(tab, null!, "")
        }

        const node = new Node(tab, null!, json?.text ?? "")
        
        node.childrenVisible = json.childrenVisible ?? true
        node.visible = json.visible ?? true
        node.selected = json.selected ?? false
        if(node.selected)
        {
            tab.selectNodes(node, false)
        }
        node.completion = json.completion ?? 0

        if(json.children != null)
        {
            node.createChildrenFromJsonRecursive(json.children)
        }

        if(json.tags != null)
        {
            for(const [name, value] of Object.entries(json.tags))
            {
                node.setTag(name, value)
            }
        }

        return node
    }

    export function fromText(tab: Tab, text: string): Node[]
    {
        const lines = text.split(/[\n\r]/g)

        const rootNodes: Node[] = []
        const layerNodeStack: Node[] = []

        let previousIndent = 0
        for(let line of lines)
        {
            let indent = 0

            while(line.startsWith("    "))
            {
                line = line.slice(4)
                indent++
            }

            while(line.startsWith("\t"))
            {
                line = line.slice(1)
                indent++
            }

            line = line.trim()

            let parentNode: Node

            if(indent == 0)
            {
                layerNodeStack.length = 0
                console.log(`Creating root node with text: ${line}`)
                
                parentNode = new Node(tab, null!, line)
                rootNodes.push(parentNode)
            }
            else
            {
                if(indent < previousIndent)
                {
                    //Go out
                    console.log(`Going out from indent ${previousIndent} to ${indent}`)

                    layerNodeStack.splice(indent, layerNodeStack.length - indent)
                }
                else if(indent == previousIndent)
                {
                    //That's the spot
                    console.log(`Staying on the same indent ${indent}`)
                    
                    layerNodeStack.pop()
                }
                else if(previousIndent < indent)
                {
                    console.log(`Going deeper from indent ${previousIndent} to ${indent}`)
                    //Go deeper owo
                }

                parentNode = new Node(tab, getLast(layerNodeStack), line)
            }

            layerNodeStack.push(parentNode)

            previousIndent = indent
        }

        return rootNodes
    }
}

