export function getClosestNodeToPosition(pos: Pos, goalRectPoint: Direction2D9 = Direction2D9.Center, distanceLimit: number = Number.POSITIVE_INFINITY, filter: (node: Node) => boolean = noopTrue): [Node, number]
{
    let closestNode: Node = null!
    let closestDistance = Number.POSITIVE_INFINITY

    for(const node of nodesMap.values())
    {
        if(node.el == null)
        {
            continue
        }

        if(!node.alive)
        {
            continue
        }

        if(!filter(node))
        {
            continue
        }

        const boundingBox = node.el.getBoundingClientRect()
        const goalPos: Pos = getRectPoint(boundingBox, goalRectPoint)
        const rectWorldX = goalPos.x - get(currentCamera).x
        const rectWorldY = goalPos.y - get(currentCamera).y

        const distanceSq = ((rectWorldX - pos.x) ** 2) + ((rectWorldY - pos.y) ** 2)

        if(distanceSq < closestDistance)
        {
            closestDistance = distanceSq
            closestNode = node
        }
    }

    
    if(distanceLimit <= 0 || closestDistance <= distanceLimit ** 2)
    {
        return [closestNode, closestDistance]
    }

    return [null!, Number.POSITIVE_INFINITY]
}

export function multiDeleteNodes(nodes: Iterable<Node>)
{
    const tasks: TaskMapAction[] = []

    for(const node of nodes)
    {
        if(node.isRoot)
        {
            continue
        }

        if(!node.alive)
        {
            continue
        }

        const children = node.getAliveChildrenRecursive()

        tasks.push(new DeleteNodeAction(node.parent.id, node.id, node.childIndex, children))

        node.delete(false)
    }

    addActionToHistory(new MultiTaskMapAction(tasks))
}

export function shouldSelectParentNodeOnElClick(clickedEl: HTMLElement)
{
    for(const elClass of clickedEl.classList)
	{
        const lowercaseClass = elClass.toLowerCase()

		if(lowercaseClass.includes("checkbox"))
		{
			return false
		}
        else if(lowercaseClass.includes("toggle"))
        {
            return false
        }
	}

    return true
}

export function nodesSetToArray(nodesSet: Set<Node>): Node[]
{
    const nodes = [...nodesSet]

    nodes.sort((a, b) => a.childIndex - b.childIndex)

    return nodes
}

