<script lang="ts">
import NodeComp from "./NodeComp.svelte";
import { shouldSelectParentNodeOnElClick, type Node } from "../comps_data/nodes.svelte";
import { SHOW_HIDE_TOGGLE_SIZE, SHOW_HIDE_TOGGLE_SIZE_HALF } from "../data/finals";
import { projectConfig } from "../data/projectConfig";
import TagComp from "./TagComp.svelte";
import { playPopSound } from "../data/audio";
import { getEventTargetNode } from "../util/util.svelte";

// export let node: Node

const { node } : { node: Node } = $props()
// export let node: Node

// console.log(`node: ${typeof(node)}`)
// console.log(node)

//#endregion input box
function bindElToNode(el: HTMLElement)
{
	node.setEl(el)
}

function bindLine(el: SVGLineElement, node: Node)
{
	node.lineToParentEl = el;
}

//region onDoubleClick
function onDoubleClick(e: MouseEvent)
{
	const [node, depth, els] = getEventTargetNode(e)

	if(node == null)
	{
		return
	}

	if(node.editing)
	{
		return
	}

	const clickedEl = els[0]

	if(!shouldSelectParentNodeOnElClick(clickedEl))
	{
		return
	}

	console.log(clickedEl.classList)

	if(node != null)
	{
		node.startEditing()
	}
}
</script>

<style>
	.node
    {
		position: absolute;
		background: pink;

		border-radius: 8px;
		padding: 16px;

		align-items: flex-start;
		justify-content: center;

		display: flex;
		flex-direction: row;

		width: max-content;
	}

	.node_content
    {
		align-items: flex-start;
		justify-content: center;

		display: flex;
		flex-direction: column;

		width: max-content;
	}

	.text, .label
	{
		font: inherit;

		resize: both;
		border: none;
		white-space: pre;
		align-self: center;

		width: fit-content;
		max-width: 100%;
		min-width: 0;

		opacity: 90%;
	}

	.label
	{
		user-select: none;
		pointer-events: none;
	}

	.showHideToggle
    {
        position: absolute;
        border-radius: 50%;
        background: transparent;
		pointer-events: auto;
		opacity: 0%;
    }

	.tags
	{
		display: flex;
		flex-wrap: wrap;
		align-items: center;
		gap: 2px;

		left: 0;
		top: 100%;
		margin: 2px;
	}

	.checkbox
    {
        display: flex;
        align-items: center;
        justify-content: center;

        font-size: 24px;
        width: 24px;
        height: 24px;

        cursor: pointer;
        user-select: none;
    }
</style>

<!-- svelte-ignore a11y_no_static_element_interactions -->
<div
	class="node"

	ondblclick={onDoubleClick}

	// bind:this={node.el}
	use:bindElToNode
	data-id={node.id}
	tabindex=0
	role="button"
	class:selected={node.selected}

	//#region style
	style:left="{node.pos.x}px"
	style:top="{node.pos.y}px"
	style:display="{node.visible ? 'flex' : 'none'}"
	style:align-items="center"
	style:flex-direction="column"
	style:opacity={node.opacity}
	style:max-width={node.style.get("maxWidth") + "px"}
	style:max-height={node.style.get("maxHeight") + "px"}

	// style:left="{node.pos.x}px"
	// style:top="{node.pos.y}px"

	style:min-width="{projectConfig.get("NODE_MIN_WIDTH")}px"
	style:min-height="{projectConfig.get("NODE_MIN_HEIGHT")}px"
	
	style:background={node.getBackgroundColor()}

	style:pointer-events={node.alive ? 'auto' : 'none'}
	// style:z-index={node.getZIndex()}
	//#endregion style
>
	<div
		class="node_content"
		>

		<!-- parent line -->
		<!-- direct line -->
		{#if node.lineToParentNode != null}
		<svg 
			style="position: absolute; left: 0; top: 0; pointer-events: none; overflow: visible;"
		>
			<line
				use:bindLine={node.lineToParentEl, node}
				style:display={node.lineToParentNode.alive ? 'block' : 'none'}
				x1={node.lineToParentPos1.x}
				y1={node.lineToParentPos1.y}
				x2={node.lineToParentPos2.x}
				y2={node.lineToParentPos2.y}
				style:stroke={node.lineStroke}
				style:background={node.backgroundColor}
				stroke-width="3"
			/>
		</svg>
		{/if}

		<!-- show/hide toggle -->
		<!-- svelte-ignore binding_property_non_reactive -->
		{#if node.anyChildrenAlive()}
			<button class="showHideToggle"
				tabindex=-1
				bind:this={node.showHideToggleEl}
				style:opacity={node.showHideToggleOpacity}
				onmouseenter={(e) =>
				{
					node.hovered = true
				}}
				onmouseleave={(e) =>
				{
					node.hovered = false
				}}
				style:display={node.alive && !node.editing ? 'block' : 'none'}
				style:width={`${SHOW_HIDE_TOGGLE_SIZE}px`}
				style:height={`${SHOW_HIDE_TOGGLE_SIZE}px`}
				style:left={`${node.size.x}px`}
				style:top={`${(node.size.y/2) - SHOW_HIDE_TOGGLE_SIZE_HALF}px`}
				style:color="black"
				style:background={node.childrenVisible ? 'white' : 'grey'}
				// style:border-color={node.showChildren ? 'white' : 'grey'}
				onclick={() =>
				{
					node.toggleChildrenVisible()
				}}
			>
				{node.childrenVisible ? "-" : "+"}
			</button>
		{/if}

		<!-- children -->
		{#if node.childrenVisible}
			{#each node.children as childSvelteNode (childSvelteNode.id)}
				<!-- node itself -->
				<NodeComp
					node={childSvelteNode}
				/>
			{/each}
		{/if}

		<!-- text -->
		<textarea class="input text"
			bind:this={node.textEl}
			oninput={(event) => node.onInput(event.currentTarget)}
			// style:z-index={node.getZIndex() + 1}
			style:display={node.editing ? 'block' : 'none'}
			
			onblur={() =>
			{
				node.stopEditing(true)
			}}

			style:color={node.getDynamicColorForItem("textColor", node)}
		>
		</textarea>

		<!-- <div class="text"
			bind:this={node.textEl}
			contenteditable="true"
			on:input={(el) => updateEditingBoxSize(el.currentTarget)}
			style:display={node.editing ? 'block' : 'none'}
			
			on:blur={() =>
			{
				node.stopEditing(true)
			}}

			style:color={node.getDynamicColor("textColor", node)}
		>
		</div> -->

		<div class="label"
			style:color={node.getDynamicColorForItem("textColor", node)}

			bind:this={node.labelEl}
			style:display={node.editing ? 'none' : 'block'}
			style:pointer-events="visible"
		>
			<!-- {node.id} | {node.childIndex ?? "?"} | fatness: {node.height} | totalFatness: {node.totalHeight} | {node.text} -->
			{#if node.text.length > 0}
				{@html node.formattedText}
			{/if}

			<!-- <div>{node.size.x} | {node.size.y}</div>
			{#if node.el != null}
			{node.el.offsetWidth} | {node.el.offsetHeight}
			{/if} -->
		</div>
		<!-- region tags -->
		{#if node.tagsComps.length > 0}
			<div class="tags"
			style:color={node.getDynamicColorForItem("textColor", node)}
			style:-webkit-text-stroke={`${node.style.get("textOutlineSize")} ${node.getDynamicColorForItem("textOutlineColor", node)}`}

				style:max-width={node.style.get("maxWidth") + "px"}
			>
				{#each node.tagsComps as tag (tag.id)}
					<TagComp
						tag={tag}
					/>
				{/each}
			</div>
		{/if}
		<!-- endregion tags -->
	</div>

	<button
		bind:this={node.checkboxEl}
		class="checkbox"
		style:background={node.getCheckboxBackgroundColor()}
		style:color={node.getCheckboxColor()}
		onclick={() => { node.toggleCompleted(); playPopSound() }}
	>
	{node.checkboxSymbol}
	</button>
</div>