import { mount } from 'svelte'
import './app.css'
import App from './App.svelte'
import { messages } from './comps_data/messages.svelte'

const app = mount(App,
{
    target: document.getElementById('app')!,
})

window.addEventListener("error", event =>
{
    const text = `Error:\n${event.error instanceof Error ? event.error.message : String(event.error)}\nAt ${event.filename}:${event.lineno}:${event.colno}`
    console.error(text)
    messages.addErrorMessage(text)
})

window.addEventListener("unhandledrejection", event =>
{
    const text = `Error:\n${event.reason instanceof Error ? event.reason.message : String(event.reason)}`
    console.error(text)
    messages.addErrorMessage(text)
})

export default app