
const POP_SOUND_PATH = "./src/assets/sounds/audio-volume-change.oga"

export const POP_SOUND = new Audio(POP_SOUND_PATH)

const queuedSounds: HTMLAudioElement[] = []
let nextPlayAvailableFromMs = 0
let queueTimeoutId: number = null!

export async function playOrQueueSound(sound: HTMLAudioElement)
{
    const nowMs = Date.now()
    const gapMs = nextPlayAvailableFromMs - nowMs

    if (gapMs > 0)
    {
        queuedSounds.push(sound)

        if (queueTimeoutId == null)
        {
            queueTimeoutId = setTimeout(() =>
            {
                const nextSound = queuedSounds.shift()

                if (nextSound != null)
                {
                    playOrQueueSound(nextSound)
                }
            }, gapMs)
        }
    }
    else
    {
        nextPlayAvailableFromMs = Date.now() + 1000
        await playSound(sound)
    }
}

export async function playSound(sound:HTMLAudioElement)
{
    sound.currentTime = 0
    try
    {
        await sound.play()
    }
    catch(e)
    {
        
    }
}

export function playPopSound()
{
    playSound(POP_SOUND)
}