function msSinceTouchStart()
{
	return Date.now() - touchStartedOn
}

function onTouchStart(e: TouchEvent)
{
	wasPinching = false

	touchButton = 2

	lastMultiTouchPos = getTouchesCenterPos(e.touches)
	touchCount = e.touches.length

	if(e.touches.length == 1)
	{
		const [node, depth, els] = getEventTargetNode(e)

		if(node == null)
		{
			if(depth == 1)
			{
				touchButton = 2
			}
		}
	}

	handlePointerDown(e, lastMultiTouchPos.x, lastMultiTouchPos.y, touchButton)
}

//region onMouseDown
function onMouseDown(e: MouseEvent)
{
	handlePointerDown(e, e.clientX, e.clientY, e.button)
}

function handlePointerDown(e: UIEvent, x: number, y: number, button: number)
{
	clickDownMs[button] = Date.now()
	pointerStates[button] = true
	pointerLast.x = x
	pointerLast.y = y

	// log(`pointerLast updated: ${softToFixed(pointerLast.x)}, ${softToFixed(pointerLast.y)}`)

	const camera = get(currentCamera)

	// camera.setPosition(0, 0, false)
	// camera.setZoom(1)

	const [node, depth, els] = getEventTargetNode(e)

	// if(node != null)
	// {
	// 	console.log(depth)
	// 	node.printDebugInfo()
	// }

	const clickedEl = els[0]

	if(!shouldSelectParentNodeOnElClick(clickedEl))
	{
		return
	}

	if(node != null)
	{
		if(tabIndexFocusedNode != node)
		{
			tabIndexUsingKeyboard = false
		}
	}

	// messages.addDebugMessage(`root mouse down: ${button} | node: ${node != null ? node.id : "null"}`)

	const tab = get(currentTab)
	
	switch(button)
	{
		case 0:
		{
			lastPointerDownPos.x = x
			lastPointerDownPos.y = y

			let startDragging = node == null

			if(startDragging)
			{
				const clickedElKeys = Object.keys(clickedEl)

				const clearSelection = !modifierStates[0] && !modifierStates[1] && clickedElKeys.length == 0

				if(clearSelection)
				{
					tab.deselectNodes()
				}
				else
				{
					selectedNodesAtSelectionBoxDragging = new Set(tab.selectedNodes)
				}

				selectionBoxDragStartPos.x = x
				selectionBoxDragStartPos.y = y

				selectionBoxDragWorldStartPos.x = (x - get(currentCamera).x) / get(currentCamera).zoom
				selectionBoxDragWorldStartPos.y = (y - get(currentCamera).y) / get(currentCamera).zoom

				selectionBoxDragging = true
			}
			else
			{
				//Node selected

				if(tabIndexFocusedNode != null)
				{
					if(node != tabIndexFocusedNode)
					{
						unfocusTabIndex()
					}
				}

				if
				(
					modifierStates[1] &&
					tab.lastSelectedNode != null &&
					tab.lastSelectedNode !== node &&
					tab.lastSelectedNode.parent == node.parent
				)
				{
					const deselectNodes = !modifierStates[0]

					if(deselectNodes)
					{
						tab.deselectNodes()
					}

					const lastSelectedNodeIndex = tab.lastSelectedNode.childIndex
					const nodeIndex = node.childIndex

					const from = Math.min(lastSelectedNodeIndex, nodeIndex)
					const to = Math.max(lastSelectedNodeIndex, nodeIndex)

					for(let i = from; i <= to; i++)
					{
						tab.selectNodes(node.parent.children[i], false)
					}
				}
				else if(modifierStates[0] || modifierStates[1])
				{
					if(tab.selectedNodes.has(node))
					{
						tab.deselectNodes(node)
					}
					else
					{
						tab.selectNodes(node, false)
					}
				}
				else
				{
					if(node.selected)
					{
						const nodesToDeselect: Set<Node> = new Set(tab.selectedNodes)

						nodesToDeselect.delete(node)

						tab.deselectNodes(nodesToDeselect)
					}
					else
					{
						tab.selectNodes(node, true)
					}
				}
			}
		}
		break

		case 1:
			for(const node of tab.nodes)
			{
				if(!node.alive)
				{
					continue
				}

				console.log(`${node.id}: ${node.isOnScreen()}`)
			}

			get(currentCamera).resetPositionAndZoom()
			break
			
		case 2:
			break
	}
}

//region onMouseUp
