function handlePointerUp(e: UIEvent, button: number)
{
	const tab = get(currentTab)
	// const node = getMouseEventTargetNode(e)

	pointerStates[button] = false
	// console.log('root mouse up', e.button)

	switch(button)
	{
		case 0:
		{
			selectionBoxDragging = false
			selectedNodesAtSelectionBoxDragging.clear()

			// deselectNodes()
			// for(const node of nodesMap.values())
			// {
			// 	if(node.anyPointWithinRect(dragStart.x, dragStart.y, e.clientX, y))
			// 	{
			// 		selectNodes(node, false)
			// 	}
			// }
			// console.log(`Selected ${selectedNodes.size} nodes!`)

			if(dragToNode != null)
			{
				// console.log(`Moved node ${draggingNode.id} to ${dragToNode.id}'s ${Direction[dragToNodeDirection]}!`)

				const selectedNodesArray = tab.getSelectedNodesAsArray()

				let attachNode: (node: Node) => void
				let i = 0

				switch(dragToNodeDirection)
				{
					case Direction2D4.Up:
					case Direction2D4.Down:
					{
						const up = dragToNodeDirection == Direction2D4.Up

						attachNode = node =>
						{
							draggingNode.attachToParent(dragToNode.parent, i++ + dragToNode.childIndex + (up ? 0 : 1))
						}
					}
					break

					case Direction2D4.Right:
					{
						attachNode = node =>
						{
							draggingNode.attachToParent(dragToNode)
						}
					}
					break

					default:
					{
						throw new Error("Invalid dragToNodeDirection: " + dragToNodeDirection)
					}
					break
				}

				for(const node of selectedNodesArray)
				{
					attachNode(node)
				}

				dragToNode.updateTreeRecursive()
			}

			stopDraggingNode()

			if(tab.lastSelectedNode != null)
			{
				if(!tab.lastSelectedNode.isRoot)
				{
					tab.lastSelectedNode.parent.updateChildren()
				}
			}
		}
		break

		case 1:
		{

		}
		break

		case 2:
		{

		}
		break
	}
}

function stopDraggingNode()
