function onMouseWheel(e: WheelEvent)
{
	const direction = getMouseWheelEventDirection(e)
	// messages.addDebugMessage(`mouse wheel: deltaY: ${e.deltaY} | ${Direction2D4[direction]}`)

	const [node, depth, els] = getEventTargetNode(e)

	if(els.length > 0)
	{
		handleScroll(direction, direction == Direction2D4.Up ? 1.1 : 0.9)
	}

	// e.preventDefault()
	// e.stopPropagation()
}

function handleScroll(direction: Direction2D4, zoomScale: number, x: number = pointerLast.x, y: number = pointerLast.y)
{
	const camera = get(currentCamera)

	if(camera == null)
	{
		messages.addErrorMessage("Camera is null in handleScroll")
	}

	// log(`direction: ${Direction2D4[direction]}, scrollSpeed: ${softToFixed(zoomScale)}, x: ${x}, y: ${y}`)

	switch(direction)
	{
		case Direction2D4.Up:
			camera.scaleZoom(zoomScale, { x, y }, false)
			break

		case Direction2D4.Down:
			camera.scaleZoom(zoomScale, { x, y }, false)
			break

		case Direction2D4.Left:
			camera.offsetPosition(userConfig.get("SCROLL_SIDE_MOVE_SPEED"), 0, false)
			break

		case Direction2D4.Right:
			camera.offsetPosition(-userConfig.get("SCROLL_SIDE_MOVE_SPEED"), 0, false)
			break
	}
}

