//region onTouchMove
let lastTouchDistanceFromCenter = 0
let lastMultiTouchPos: Pos = { x: 0, y: 0 }
let touchCount = 0
let wasPinching = false

function onTouchMove(e: TouchEvent)
{
	if(touchCount != e.touches.length)
	{
		onTouchStart(e)
	}

	const centerPos = getTouchesCenterPos(e.touches)

	// log(`touchCount: ${touchCount}`)

	// const camera = get(currentCamera)
	// camera.setPosition(0, 0, false)
	// camera.setZoom(0)

	let shouldPan = false
	
	if(e.touches.length == 1)
	{
		shouldPan = true
	}
	if(e.touches.length >= 2)
	{
		shouldPan = true

		// log(`centerPos: ${centerPos.x}, ${centerPos.y} | lastMultiTouchPos: ${lastMultiTouchPos.x}, ${lastMultiTouchPos.y}`)

		const touchDistanceFromCenterSq = distanceSqRaw(e.touches[0].clientX, e.touches[0].clientY, centerPos.x, centerPos.y)

		if(touchDistanceFromCenterSq != 0)
		{
			const thisDistance = Math.sqrt(touchDistanceFromCenterSq)
			if(!wasPinching)
			{
				wasPinching = true
				lastTouchDistanceFromCenter = thisDistance
			}
			const distanceChange = thisDistance - lastTouchDistanceFromCenter
	
			if(distanceChange != 0)
			{
				const zoomScale = 1 + distanceChange / 150
		
				const direction = distanceChange > 0 ? Direction2D4.Up : Direction2D4.Down
		
				// log(Direction2D4[direction])
				// log(`${softToFixed(zoomScale)}`)
		
				handleScroll(direction, zoomScale, centerPos.x, centerPos.y)
		
				lastTouchDistanceFromCenter = thisDistance
			}
		}
	}

	if(shouldPan)
	{
		handlePointerMove(e, centerPos.x, centerPos.y)
	}

	lastMultiTouchPos = centerPos
}

//region onMouseMove
function onMouseMove(e: MouseEvent)
{
	handlePointerMove(e, e.clientX, e.clientY)
}

function handlePointerMove(e: UIEvent, x: number, y: number)
{
	const camera = get(currentCamera)

	const dx = x - pointerLast.x
	const dy = y - pointerLast.y

	pointerLast.x = x
	pointerLast.y = y

	pointerWorldLast.x = (x - camera.x) / camera.zoom
	pointerWorldLast.y = (y - camera.y) / camera.zoom

	pointerCircle.moveTo(pointerWorldLast)
	// console.log(`moveNodeIndicatorCircle: ${moveNodeIndicatorCircle.goalPos.x} ${moveNodeIndicatorCircle.goalPos.y}`)
	
	// log(`mouse move ${softToFixed(dx)} ${softToFixed(dy)}`)

	if (pointerStates[2])
	{
		camera.offsetPosition(dx, dy, false)
	}
	else if(pointerStates[0])
	{
		// for(const node of selectedNodes)
		// {
		// 	node.x += dx / get(currentCamera).zoom
		// 	node.y += dy / get(currentCamera).zoom
		// }

		if(selectionBoxDragging)
		{
			doSelectionBoxDrag()
		}
		else if(draggingNode == null)
		{
			const tab = get(currentTab)

			const node = [...tab.selectedNodes][0]
			if(!node.isRoot)
			{
				if(!node.editing)
				{
					draggingNodes.clear()
					draggingRootNodes.length = 0

					draggingNode = node

					draggingNode.forThisAndEachChildRecursive(node => draggingNodes.add(node))
					draggingNodes.add(node.rootNode)
				}
			}
		}
		else
		{
			// console.log(`Moving node ${node.id} by dx: ${dx}, dy: ${dy}`)
			draggingNode.clearMoveAnimation()
			draggingNode.offsetPosition(dx / camera.zoom, dy / camera.zoom, false)
		}
	}
	
	if(draggingNode != null)
	{
		const distanceDragged = distanceSq(lastPointerDownPos, pointerLast)

		if(isWithinDraggingDistanceSq(distanceDragged))
		{
			const [closestNodeVertical, distanceVertical] = findClosestNodeFromTheirPoint(draggingNode, Direction2D9.Center, Direction2D9.Center, node => !draggingNodes.has(node))
			const [closestNodeHorizontal, distanceHorizontal] = findClosestNodeFromTheirPoint(draggingNode, Direction2D9.Right, Direction2D9.Left, node => !draggingNodes.has(node) && node.children.length == 0)

			// if(userConfig.get("DEBUG"))
			// {
			// 	if(closestNodeHorizontal != null)
			// 	{
			// 		console.log(`Closest horizontal node: ${closestNodeHorizontal.id}, distance: ${distanceHorizontal}`)
			// 	}
	
			// 	if(closestNodeVertical != null)
			// 	{
			// 		console.log(`Closest vertical node: ${closestNodeVertical.id}, distance: ${distanceVertical}`)
			// 	}
			// }

			if(closestNodeHorizontal == null && closestNodeVertical != null)
			{
				previewDragToNode(closestNodeVertical, true)
			}
			else if(closestNodeHorizontal != null && closestNodeVertical == null)
			{
				previewDragToNode(closestNodeHorizontal, false)
			}
			else if(closestNodeHorizontal != null && closestNodeVertical != null)
			{
				if(distanceVertical < distanceHorizontal)
				{
					const closestNodeVerticalTopPos = getRectPoint(closestNodeVertical.getWorldRect(), Direction2D9.Top)
					const closestNodeVerticalBottomPos = getRectPoint(closestNodeVertical.getWorldRect(), Direction2D9.Bottom)
					
					const draggingNodeVerticalTopPos = getRectPoint(draggingNode.getWorldRect(), Direction2D9.Top)
					const draggingNodeVerticalBottomPos = getRectPoint(draggingNode.getWorldRect(), Direction2D9.Bottom)

					const closestNodeShortestVerticalDistance = Math.min(distanceSq(draggingNodeVerticalBottomPos, closestNodeVerticalTopPos), distanceSq(draggingNodeVerticalTopPos, closestNodeVerticalBottomPos))

					if(closestNodeShortestVerticalDistance * 5 < distanceHorizontal)
					{
						previewDragToNode(closestNodeVertical, true)
						
					}
					else
					{
						previewDragToNode(closestNodeHorizontal, true)
					}
				}
				else
				{
					previewDragToNode(closestNodeHorizontal, false)
				}
			}
			else
			{
				cancelNodeDragPreview()
			}
		}
		else
		{
			cancelNodeDragPreview()
		}
	}
}

export function raycastGrid(worldOrigin: Pos, direction: Pos, onStep: (matches: HTMLElement[], pos: Pos, step: number, distance: number) => boolean, stepSize: number = projectConfig.get("NODE_MIN_HEIGHT"), maxDistance: number = Infinity)
{
	let step = 0
	let distance = 0

	direction = normalizeVec2(direction)

	const worldToViewportOrigin =
	{
		x: worldOrigin.x * get(currentCamera).zoom + get(currentCamera).x,
		y: worldOrigin.y * get(currentCamera).zoom + get(currentCamera).y,
	}

	while(distance < maxDistance)
	{
		const pos =
		{
			x: worldToViewportOrigin.x + direction.x * distance,
			y: worldToViewportOrigin.y + direction.y * distance,
		}

		if(!isWithinRange(pos.x, 0, window.innerWidth) || !isWithinRange(pos.y, 0, window.innerHeight))
		{
			return false
		}

		const elements = document.elementsFromPoint(pos.x, pos.y)
		const htmlElements: HTMLElement[] = elements.filter(el => el instanceof HTMLElement) as HTMLElement[]

		const stop = onStep(htmlElements, pos, distance / stepSize, distance)

		if(stop)
		{
			return true
		}

		distance += stepSize
		step++
	}
}

export function raycastGridForNodes(worldOrigin: Pos, direction: Pos, onStep: (node: Node, pos: Pos, step: number, distance: number) => boolean, stepSize: number = projectConfig.get("NODE_MIN_HEIGHT"), maxDistance: number = Infinity)
{
	return raycastGrid(worldOrigin, direction, (elements, pos, step, distance) =>
	{
		for(const el of elements)
		{
			const node = getNodeFromHTMLElement(el, false)[0]

			if(node != null)
			{
				const stop = onStep(node, pos, step, distance)

				if(stop)
				{
					return true
				}
			}
		}

		return false
	}, stepSize, maxDistance)
}

function doSelectionBoxDrag()
{
	return

	if(!selectionBoxDragging)
	{
		return
	}

	if(distanceSq(selectionBoxDragStartPos, pointerLast) < 25 ** 2)
	{
		return
	}

	const tab = get(currentTab)

	let nodesToSelect: Set<Node>

	const useSavedSelectedNodes = modifierStates[0] || modifierStates[1]

	if(useSavedSelectedNodes)
	{
		nodesToSelect = new Set<Node>(selectedNodesAtSelectionBoxDragging)
	}
	else
	{
		selectionBoxDraggingSelectedNodesCache.clear()
		nodesToSelect = selectionBoxDraggingSelectedNodesCache
	}

	let selectionMode: number = 0

	if(modifierStates[0] && modifierStates[1])
	{
		//invert
		selectionMode = 2
	}
	else if(modifierStates[0])
	{
		//remove
		selectionMode = 1
	}
	else if(modifierStates[1])
	{
		//add
		selectionMode = 0
	}

	const nodes = tab.nodes
	
	for(const node of nodes)
	{
		if(node.isCollidingWithRect(selectionBoxDragWorldStartPos.x, selectionBoxDragWorldStartPos.y, pointerWorldLast.x, pointerWorldLast.y))
		{
			switch(selectionMode)
			{
				case 0:
					nodesToSelect.add(node)
					break

				case 1:
					nodesToSelect.delete(node)
					break

				case 2:
				if(nodesToSelect.has(node))
				{
					nodesToSelect.delete(node)
				}
				else
				{
					nodesToSelect.add(node)
				}
				break
			}
		}
	}

	tab.selectNodes(nodesToSelect, true)
}

function previewDragToNode(draggedToNode: Node, verticalOrHorizontal: boolean)
{
	const draggedToNodeCenter = getRectCenter(draggedToNode.getWorldRect())
	const draggingNodeCenter = getRectCenter(draggingNode.getWorldRect())

	if(verticalOrHorizontal)
	{
		draggingNode.lineToParentNode = draggedToNode.parent
	}
	else
	{
		draggingNode.lineToParentNode = draggedToNode
	}

	dragToNode = draggedToNode
	if(verticalOrHorizontal)
	{
		dragToNodeDirection = draggingNodeCenter.y < draggedToNodeCenter.y ? Direction2D4.Up : Direction2D4.Down
	}
	else
	{
		dragToNodeDirection = Direction2D4.Right
	}

	if(userConfig.get("DEBUG"))
	{
		moveNodeIndicatorCircle.setVisible(true)
		const worldRect = draggedToNode.getWorldRect()
		const tab = get(currentTab)
		scaleRect(worldRect, 1 / get(currentCamera).zoom)
		moveNodeIndicatorCircle.moveTo(getRectPoint(worldRect, Direction2D4.toDirection2D9(dragToNodeDirection)))
	}
}

function findClosestNodeFromTheirPoint(fromNode: Node, toGoalPoint: Direction2D9 = Direction2D9.Center, fromOriginPoint: Direction2D9 = Direction2D9.Center, filter: (node: Node) => boolean = noopTrue): [ Node, number ]
{
	const lookFromPos = getRectPoint(fromNode.getWorldRect(), fromOriginPoint)

	const result = getClosestNodeToPosition(lookFromPos, toGoalPoint, 300, filter)

	return result
}

function cancelNodeDragPreview()
{
	if(draggingNode != null)
	{
		draggingNode.lineToParentNode = draggingNode.parent
	}
	
	moveNodeIndicatorCircle.setVisible(false)
	dragToNode = null!
	dragToNodeDirection = null!
}
