function handleKeyDown(e: KeyboardEvent)
{
	lastKeyPressed = e.key.toLowerCase()
	// messages.addDebugMessage(`keydown: ${lastKeyPressed} | ${e.code} | ${e.keyCode} | isTyping: ${isTyping()}`)
	
	switch(lastKeyPressed)
	{
		case "control":
			modifierStates[0] = true
			doSelectionBoxDrag()
			break

		case "shift":
			modifierStates[1] = true
			doSelectionBoxDrag()
			break
		
		case "alt":
			modifierStates[2] = true
			break
	}

	switch(lastKeyPressed)
	{
		case "tab":
		{
			tabIndexUsingKeyboard = true
		}
		break
	}

	let cancelOriginalAction = false

	const tab = get(currentTab)
	const firstNode = tabIndexFocusedNode ?? tab != null ? (tab.selectedNodes.size > 0 ? [...tab.selectedNodes][0] : null) : null
	const isCurrentlyTyping = isTyping()

	if(isCurrentlyTyping)
	{
		//#region not typing
		if(firstNode != null)
		{
			playPopSound()
	
			switch(lastKeyPressed)
			{
				default:
				{
					cancelOriginalAction = false
					break
				}
	
				case "escape":
				case "enter":
				{
					const isEnter = lastKeyPressed == "enter"

					if(isEnter && modifierStates[1])
					{
						break
					}

					firstNode.stopEditing(isEnter)
					firstNode.focus()
				}
				break

				case "shift":
				{

				}
				break
			}
		}
		//#endregion not typing
	}
	else
	{
		//#region while not typing
		const anyModifierHeld = modifierStates.some(state => state)
		const isCharTyping = isTypingChar(lastKeyPressed)

		switch(lastKeyPressed)
		{
			case " ":
			{
				if(tabIndexFocusedNode != null)
				{
					if(tabIndexFocusedNode.selected)
					{
						tab.deselectNodes(tabIndexFocusedNode)
					}
					else
					{
						tab.selectNodes(tabIndexFocusedNode, false)
					}

					cancelOriginalAction = true
				}
			}
			break
		}

		//#region specific node actions
		if(firstNode != null && !cancelOriginalAction)
		{
			if(firstNode.canEditAgain())
			{
				switch(lastKeyPressed)
				{
					default:
					{
						cancelOriginalAction = false
						break
					}

					case "f2":
					{
						firstNode.startEditing()
					}
					break

					case "delete":
					case "backspace":
					{
						tab.deleteSelectedNodes()
					}
					break

					case "escape":
					{
						if(tabIndexFocusedNode != null)
						{
							unfocusTabIndex()
						}
						else
						{
							tab.deselectNodes()
						}
					}
					break

					case "enter":
					{
						const parent = modifierStates[0] ? firstNode : firstNode.parent
						const belowNode = modifierStates[0] ? undefined : firstNode

						tab.createChildForNode(parent, belowNode)
					}
					break
				}

				if(!cancelOriginalAction)
				{
					if(isCharTyping)
					{
						if(!anyModifierHeld || AreModifiersOnly(1))
						{
							// firstNode.text += lastKeyPressed
							firstNode.startEditing()
						}
					}
				}
			}
		}
		//#endregion specific node actions

		if(!cancelOriginalAction)
		{
			//#region multi node actions
			let isKeyNavigation = false

			switch(lastKeyPressed)
			{
				case "arrowup":
				case "arrowdown":
				case "arrowleft":
				case "arrowright":
				{
					isKeyNavigation = true
				}
				break
			}

			if(isKeyNavigation)
			{
				tab.selectLastSelectedAliveNodeIfNoneSelected()
			}

			if(tab.selectedNodes.size > 0)
			{
				//#region navigation
				switch(lastKeyPressed)
				{
					case "arrowup":
					case "arrowdown":
					{
						cancelOriginalAction = true
						
						const [navigatingNodes, tabIndexMode] = getNavigatingNodes()
	
						const up = "arrowup"
						const amount = lastKeyPressed == up ? 1 : -1
	
						if(modifierStates[2])
						{
							tab.selectedNodes.forEach(node => node.move(amount))
						}
						else
						{
							const toSelect: Set<Node> = new Set()
	
							for(const node of navigatingNodes)
							{
								if(!node.isRoot)
								{
									const targetChildIndex = node.childIndex - amount
	
									if(isWithinRange(targetChildIndex, 0, node.parent.children.length - 1))
									{
										if(node.parent.children.length > 1)
										{
											const siblingNode = node.getSiblingNode(-amount, true)
											toSelect.add(siblingNode)
											continue
										}
									}
								}
	
								if(raycastGridForNodes(getRectCenter(node.getWorldRect()), { x: 0, y: -amount }, (nextNode, pos, step) =>
								{
									if(nextNode == node)
									{
										return false
									}
	
									toSelect.add(nextNode)
									return true
								}))
								{
									continue
								}
	
								toSelect.add(node)
							}
	
							selectNavigatingNodes(toSelect, tabIndexMode)
						}
					}
					break
	
					case "arrowleft":
					case "arrowright":
					{
						cancelOriginalAction = true
	
						const [navigatingNodes, tabIndexMode] = getNavigatingNodes()
	
						const left = lastKeyPressed == "arrowleft"
	
						const toSelect: Set<Node> = new Set()
	
						for(const node of navigatingNodes)
						{
							let picked = false
							
							if(left)
							{
								if(!node.isRoot)
								{
									toSelect.add(node.parent)
									picked = true
								}
							}
							else
							{
								if(node.children.length > 0 && node.childrenVisible)
								{
									toSelect.add(node.getChildVerticallyClosestToParent())
									picked = true
								}
							}
	
							if(!picked)
							{
								toSelect.add(node)
							}
						}
	
						selectNavigatingNodes(toSelect, tabIndexMode)
					}
					break
				}
				//#endregion navigation
			}
			//#endregion multi node actions
			//#endregion while not typing
		}
	}
	
	if(!cancelOriginalAction)
	{
		if(modifierStates[0])
		{
			//#region ctrl
			cancelOriginalAction = true
	
			switch(lastKeyPressed)
			{
				default:
				{
					cancelOriginalAction = false
				}
				break
	
				case "-":
				{
					get(currentCamera).scaleZoom(1 / userConfig.get("SCROLL_ZOOM_SPEED"), pointerWorldLast)
				}
				break
	
				case "+":
				case "=":
				{
					get(currentCamera).scaleZoom(userConfig.get("SCROLL_ZOOM_SPEED"), pointerWorldLast)
				}
				break
			}

			if(!cancelOriginalAction && !isTyping())
			{
				cancelOriginalAction = true

				switch(lastKeyPressed)
				{
					default:
					{
						cancelOriginalAction = false
					}
					break

					case "s":
					{
						console.log(modifierStates)

						if(modifierStates[1])
						{
							saveToGoogleDrive()
						}
						else
						{
							save("Ctrl + S")
						}
						modifierStates[0] = false
					}
					break
		
					case "o":
					{

						if(modifierStates[1])
						{
							openProjectPickerFromGoogleDrive()
						}
						else
						{
							openFilePickerProject()
						}
					}
					break

					case "p": break
		
					case "x":
					case "c":
					{
						const deleteAfter = lastKeyPressed == "x"
		
						const selectedNodesArray = tab.getSelectedNodesAsArray()
						jsonNodesClipboard = selectedNodesArray.map(node => node.toJson())
						clipboard = stringify(jsonNodesClipboard)
		
						if(jsonNodesClipboard.length > 0)
						{
							navigator.clipboard.writeText(clipboard)
						}
		
						if(deleteAfter)
						{
							multiDeleteNodes(tab.selectedNodes)
						}
					}
					break
		
					case "v":
					{
						pasteFromClipboard()
					}
					break
				
					case "z":
					{
						undo()
					}
					break
		
					case "y":
					{
						redo()
					}
					break
				}
			}
			//#endregion ctrl
		}
	}

	if(cancelOriginalAction)
	{
		e.preventDefault()
		e.stopPropagation()
	}
}

function getNavigatingNodes(): [Node[], boolean]
{
	const tabIndexMode = tabIndexFocusedNode != null

	const navigatingNodes: Node[] = []

	if(tabIndexMode)
	{
		if(tabIndexFocusedNode != null)
		{
			navigatingNodes.push(tabIndexFocusedNode)
		}
	}
	else
	{
		const tab = get(currentTab)
		addAllFromTo(tab.selectedNodes, navigatingNodes)
		unfocusTabIndex()
	}

	return [navigatingNodes, tabIndexMode]
}

function selectNavigatingNodes(toSelect: Set<Node>, tabIndexMode: boolean)
{
	if(toSelect.size > 0)
	{
		if(tabIndexMode)
		{
			;[...toSelect][0].el.focus()
		}
		else
		{
			const tab = get(currentTab)
			tab.selectNodes(toSelect, true)
		}
	}
}

