async function setProjectFromJson(json: any): Promise<boolean>
{
	const type = getJsonType(json)

	// console.log(`Setting project from JSON of type: ${type}`)

	if(type == "unknown")
	{
		return false
	}

	// console.log(`setProjectFromJson: json.config:`)
	// console.log(json.config)

	closeProject()
	incrementProjectNumber()
	projectConfig.setFromJson(json.config)
	const madeTabs: Tab[] = []
	let currentTabIndex = 0

	switch(type)
	{
		case "project":
		{
			const projectJson: ProjectJson = json as ProjectJson
			if("indexOfSelectedTab" in projectJson)
			{
				currentTabIndex = projectJson.indexOfSelectedTab
			}

			console.log(projectJson)

			if("tabs" in projectJson)
			{
				for(const tabJson of projectJson.tabs as TabJson[])
				{
					try
					{
						const tab = Tab.fromJson(tabJson)

						madeTabs.push(tab)
					}
					catch(e)
					{
						console.error("Failed to create tab from JSON:", e)
						messages.addMessage(`Failed to create tab from JSON: ${errorToString(e)}`)
						console.log(tabJson)
					}
				}
			}
		}
		break

		case "node":
		{
			const tab = Tab.fromNodeJson(json as NodeJson)

			madeTabs.push(tab)
		}
		break
	}

	if(madeTabs.length == 0)
	{
		const tab = new Tab(null!)
		const rootNode = new Node(tab, null!, "New Tab")
		tab.setRootNode(rootNode)

		madeTabs.push(tab)
	}

	const tabToSelect = softArrayGet(madeTabs, currentTabIndex) ?? getLast(madeTabs)
	
	tabs.set(madeTabs)
	await tick()
	await tabToSelect.select()

	console.log("Finished setting project from JSON!")
	console.log(`${madeTabs.length} tab${sIfNot1(madeTabs.length)} loaded!`)
	// console.log(tabToSelect)
	// console.log(tabToSelect.rootNode.toText(false))

	return true
}

