async function pasteFromClipboard()
{
	const tab = get(currentTab)

	if(tab.selectedNodes.size == 0)
	{
		messages.addMessage(`No node selected to paste into!\nSelect a node and press Ctrl + V to paste!`)
		return
	}

	messages.addMessage(`Pasting nodes...`)

	const items = await navigator.clipboard.read()
	let didSomethingWithClipboard = false

	for (const item of items)
	{
		// if(item.types.includes("image/png"))
		// {
		// 	const blob = await item.getType("image/png")

		// 	const url = URL.createObjectURL(blob)

		// 	console.log(url)
		// }
		// else

		if(item.types.includes("text/plain"))
		{
			const text = await item.getType("text/plain")
			const textData = await text.text()

			let jsonSuccess = false

			try
			{
				let parsedJson = JSON.parse(textData)
	
				if(parsedJson != null)
				{
					if(!Array.isArray(parsedJson))
					{
						parsedJson = [parsedJson]
					}

					if(parsedJson.length > 0)
					{
						if("text" in parsedJson[0])
						{
							const rootNodes = pasteFromJsonArray(parsedJson)

							if(rootNodes.length > 0)
							{
								jsonSuccess = true
							}
						}
					}
				}
			}
			catch(e)
			{
			}

			if(jsonSuccess)
			{
				didSomethingWithClipboard = true
			}
			else
			{
				tab.forEachSelectedNode(node =>
				{
					console.log(`Pasting text into node ${node.id} from clipboard:`)
					const rootNodes = Node.fromText(get(currentTab), textData)
					const actions: TaskMapAction[] = []
	
					for(const rootNode of rootNodes)
					{
						console.log(rootNode.toText(false))
						rootNode.attachToParent(node)
						actions.push(new AddNodeAction(node.id, rootNode.id, rootNode.childIndex, true))
					}

					if(rootNodes.length > 0)
					{
						addActionToHistory(new MultiTaskMapAction(actions))
						didSomethingWithClipboard = true
					}
				})
			}
		}
	}
	
	if(!didSomethingWithClipboard)
	{
		const rootNodes = pasteFromJsonArray()

		if(rootNodes.length > 0)
		{
			didSomethingWithClipboard = true
		}
	}

	if(didSomethingWithClipboard)
	{
		messages.addSuccessMessage(`Finished pasting from clipboard!`)
	}
}

function pasteFromJsonArray(jsonNodesArray: any[] = jsonNodesClipboard): Node[]
{
	if(jsonNodesArray == null)
	{
		return []
	}

	const tab = get(currentTab)
	
	const rootNodes: Node[] = []

	const actions: TaskMapAction[] = []

	const nodesToPasteTo = [...tab.selectedNodes]

	for(const node of nodesToPasteTo)
	{
		rootNodes.push(node.rootNode)
		const children = node.createChildrenFromJsonRecursive(jsonNodesArray)
		const firstLayer = children.get(0)

		if(firstLayer != null)
		{
			for(const firstLayerChild of firstLayer)
			{
				actions.push(new AddNodeAction(node.id, firstLayerChild.id, firstLayerChild.childIndex, true))
			}
		}
	}

	addActionToHistory(new MultiTaskMapAction(actions))

	// for(const rootNode of rootNodes)
	// {
	// 	rootNode.updateTreeRecursive()
	// }

	return rootNodes
}

async function saveToGoogleDrive(name: string = formatDate(new Date()))
{
	const response = await saveJsonToGoogleDrive(name, projectToJsonString(), projectConfig.get("GOOGLE_DRIVE_FILE_ID"))

	if(response != null)
	{
		const json = await response.json()

		console.log(`[saveToGoogleDrive] Received:`)
		console.log(json)

		if(isString(json.id))
		{
			projectConfig.set("GOOGLE_DRIVE_FILE_ID", json.id)
		}

		setGoogleDriveQueryPromise(setAppFilesToGoogleDriveFolder())
	}
}

async function openProjectPickerFromGoogleDrive()
{
	if(isGoogleDriveQueryInProgress())
	{
		messages.addWarningMessage("Already loading files from Google Drive...")
	}
	else
	{
		messages.addMessage("Loading files from Google Drive...")
		// popupWindowType = "open-project"
		const folderId = await createGoogleDriveAppFolderSoft()

		await setGoogleDriveQueryPromise(setAppFilesToGoogleDriveFolder(folderId))

		if(get(appFiles).length > 0)
		{
			leftSidebarOpen.set(true)
			leftSidebarSelectedTab.set(2)
		}
	}
}

async function onItemPickedFromGoogleDrive(item: AppFile)
{
	if(isGoogleDriveQueryInProgress())
	{
		messages.addMessage("Already loading files from Google Drive...")
		return
	}

	const isFolder = isAppFileFolder(item)

	console.log(`picked ${item.name}! Folder: ${isFolder}`)

	if(isFolder)
	{
		setGoogleDriveQueryPromise(setAppFilesToGoogleDriveFolder(item.id))
	}
	else
	{
		messages.addMessage(`Loading project ${item.name}...`)

		loadProjectFromGoogleDrive(item.id)
		leftSidebarOpen.set(false)
	}
}
//#endregion saving and loading
//#endregion functions
//region functions end

if(!isAppStarted())
{
	// closeProject()
	setAppStarted()

	loadInitialProject()
}
