import { derived, get, writable } from "svelte/store"
import type { AppFile } from "../util/interfaces"
import { MIMETYPE_GOOGLE_DRIVE_FOLDER } from "../data/finals"
import { currentTab } from "./tabs.svelte"
import { ControllerType } from "../util/enums"
import { messages } from "./messages.svelte"

let appStarted = false

// 0: left, 1: middle, 2: right
export const pointerStates: boolean[] = [false, false, false]

// 0: ctrl, 1: shift, 2: alt
export const modifierStates: boolean[] = [false, false, false]

export function AreModifiersOnly(...modifierIndexes: number[])
{
    for(let i = 0; i < modifierStates.length; i++)
    {
        const shouldBeHeld = modifierIndexes.includes(i)

        if(modifierStates[i] !== shouldBeHeld)
        {
            return false
        }
    }

    return true
}

export function setAppStarted()
{
    appStarted = true
}

export function isAppStarted()
{
    return appStarted
}

let typing = false

export function setTyping(value: boolean)
{
    typing = value
}

export function isTyping()
{
    return typing
}

export let appFiles = writable<AppFile[]>([])
export let leftSidebarOpen = writable<boolean>(false)
export let leftSidebarSelectedTab = writable<number>(0)

export function setAppFiles(files: AppFile[])
{
    const sortedFiles = files.sort((a, b) =>
    {
        const aIsFolder = a.mimeType === MIMETYPE_GOOGLE_DRIVE_FOLDER
        const bIsFolder = b.mimeType === MIMETYPE_GOOGLE_DRIVE_FOLDER

        if(aIsFolder && !bIsFolder)
        {
            return -1
        }
        if(!aIsFolder && bIsFolder)
        {
            return 1
        }

        const aName = a.name.toLowerCase()
        const bName = b.name.toLowerCase()

        return aName.localeCompare(bName)
    })

    appFiles.set(files)
}

export function shouldAnimate()
{
    const tab = get(currentTab)

    if(tab == null)
    {
        return false
    }

    return tab.shouldAnimate()
}

export let controllerType = writable<ControllerType>("ontouchstart" in window ? ControllerType.Touch : ControllerType.Mouse)
export let isTouch = derived(controllerType, $controllerType => $controllerType === ControllerType.Touch)

export function setControllerType(type: ControllerType)
{
    if(get(controllerType) === type)
    {
        return
    }

    messages.addMessage(`Detected ${ControllerType[type]} input!`)

    controllerType.set(type)
}

export const isDev = import.meta.env.DEV != null