export const NEW_LINE_REGEX = /[\n\r]/g
const objectToString = (obj: any) => obj.toString()

export function xChars(char: string, count: number): string
{
    let text = ""

    for(let i = 0; i < count; ++i)
    {
        text += char
    }

    return text
}

export function mapToStrings(map: Map<any, any>, ignoreEmpty: boolean = false, cloneObj: boolean = true, rainbow: boolean = true, indent: number = 0): string[]
{
    return entriesToStrings(map.entries(), ignoreEmpty, cloneObj, rainbow, indent)
}

export function entriesToStrings(entries: MapIterator<[any, any]>, ignoreEmpty: boolean = false, cloneObj: boolean = true, rainbow: boolean = true, indent: number = 0): string[]
{
    const entriesStrings: string[] = []

    for(const [key, value] of entries)
    {
        entriesStrings.push(`${chalk.cyanBright(`Key [${key.constructor.name}]:\n${toString(key, ignoreEmpty, cloneObj, rainbow, indent)}`)}\n${chalk.magentaBright(`Value [${value.constructor.name}]:\n${toString(value, ignoreEmpty, cloneObj, rainbow, indent)}`)}`)
    }

    return entriesStrings
}

export function isIterable<T>(obj: any): obj is Iterable<T>
{
    if(obj == null)
    {
        return false
    }

    return typeof obj[Symbol.iterator] === 'function'
}

export function toString(items: any | any[], ignoreEmpty: boolean = false, cloneObj: boolean = true, rainbow: boolean = true, indent: number = 0): string
{
    if(ignoreEmpty)
    {
        items = removeNullEntriesRecursive(items, ignoreEmpty, cloneObj)
    }

    let output = ""
    let padding = xChars(" ", indent)
    let isComplex = true

    if(isIterable(items) && !isString(items))
    {
        output += `${padding}[\n`
        let i = 0
        for(const item of items)
        {
            ++i

            toStringToListEntry(item, indent, (itemSuffix, toStringPadding) =>
            {
                output += `${padding}    ${chalk.bold(`[${i}/${items.length}]:`)}${itemSuffix}${toString(item, ignoreEmpty, cloneObj, rainbow, toStringPadding)}\n`
            })
        }
        output += `${padding}]`
    }
    else if(typeof items === "number")
    {
        output = `${softToFixed(items)}`
    }
    else if(items instanceof Set)
    {
        output = toString(Array.from(items), ignoreEmpty, cloneObj, rainbow, indent + 4)
    }
    else if(items instanceof Map)
    {
        output = join(mapToStrings(items, ignoreEmpty, cloneObj, rainbow, indent + 4), `\n~~~~~\n`)
    }
    else if(isPlainRecord(items))
    {
        // return stringify(items, ignoreEmpty)

        output += `${padding}{\n`
        let i = 0
        const keys = Object.entries(items)
        for(const [key, value] of keys)
        {
            ++i

            toStringToListEntry(value, indent, (itemSuffix, toStringPadding) =>
            {
                output += `${padding}    ${chalk.bold(`[${i}/${keys.length}] [${key}]:`)}${itemSuffix}${toString(value, ignoreEmpty, cloneObj, rainbow, toStringPadding)}\n`
            })
        }
        output += `${padding}}`
    }
    else
    {
        if(items != null)
        {
            if(isString(items))
            {
                items = items.replaceAll(NEW_LINE_REGEX, `\n${padding}`)
            }
            output = `${padding}${items.toString()}`
        }

        isComplex = false
    }

    if(rainbow)
    {
        if(isComplex)
        {
            output = chalkRainbowColor(output, Math.floor(indent / 4))
        }
        else
        {
            output = chalk.whiteBright(output)
        }
    }

    // if(indent == 0)
    // {
    //     if(isComplex)
    //     {
    //         console.log(output)

    //         print
    //     }
    // }
    
    return output
}

export function removeNullEntriesRecursive<T>(obj: T, ignoreEmpty: boolean, cloneObj: boolean): T
{
    if(cloneObj)
    {
        const isComplex = isComplexObject(obj)

        if(isComplex)
        {
            obj = clone(obj)
        }
    }

    const clean = (inputItem: T) =>
    {
        const item = removeNullEntriesRecursive(inputItem, ignoreEmpty, cloneObj)

        let rejected = false

        if(ignoreEmpty && isEmpty(item))
        {
            rejected = true
        }

        return { item, rejected }
    }

    if(Array.isArray(obj))
    {
        const newArray = []

        for(const item of obj)
        {
            const cleanResult = clean(item)

            if(cleanResult.rejected)
            {
                continue
            }

            newArray.push(cleanResult.item)
        }

        obj = newArray as any
    }
    else if(obj instanceof Set)
    {
        obj.delete(null)
        obj.delete(undefined)

        for(const item of obj)
        {
            obj.delete(item)

            const cleanResult = clean(item)

            if(cleanResult.rejected)
            {
                continue
            }

            obj.add(removeNullEntriesRecursive(cleanResult.item, ignoreEmpty, cloneObj))
        }
    }
    else if(isPlainRecord(obj))
    {
        for(const [key, value] of Object.entries(obj))
        {
            if(value == null)
            {
                delete obj[key]
                continue
            }

            const cleanResult = clean(value as any)

            if(cleanResult.rejected)
            {
                delete obj[key]
                continue
            }

            (obj as any)[key] = removeNullEntriesRecursive(cleanResult.item, ignoreEmpty, cloneObj)
        }
    }
    else if(obj instanceof Map)
    {
        for(const [key, value] of obj.entries())
        {
            if(value == null)
            {
                obj.delete(key)
                continue
            }

            const cleanResult = clean(value as any)

            if(cleanResult.rejected)
            {
                obj.delete(key)
                continue
            }

            obj.set(key, removeNullEntriesRecursive(cleanResult.item, ignoreEmpty, cloneObj))
        }
    }

    return obj
}

export function isPlainRecord(value: unknown): value is Record<string, unknown>
{
    if (typeof value !== 'object' || value === null) return false

    const proto = Object.getPrototypeOf(value)
    return proto === Object.prototype || proto === null
}

export function isEmpty(obj: any): boolean
{
    if(obj == null)
    {
        return true
    }

    if(obj == undefined)
    {
        return true
    }

    if(isString(obj))
    {
        return obj.length == 0
    }

    if(Array.isArray(obj))
    {
        return obj.length == 0
    }
    
    if(isPlainRecord(obj))
    {
        return Object.keys(obj).length == 0
    }
    
    if(obj instanceof Map)
    {
        return obj.size == 0
    }
    
    if(obj instanceof Set)
    {
        return obj.size == 0
    }

    return false
}

export function clone(obj: any): any
{
    return Object.assign({}, obj)
}

export function isString(input: any): input is string
{
    return typeof input === 'string' || input instanceof String
}

export function isComplexObject(item: any): boolean
{
    if(Array.isArray(item))
    {
        return true
    }
    else if(item instanceof Set)
    {
        return true
    }
    else if(item instanceof Map)
    {
        return true
    }
    else if(isPlainRecord(item))
    {
        return true
    }

    return false
}

export const CHALK_RAINBOW_COLORS =
[
    'red',
    'orange',
    'yellow',
    'green',
    'blue',
    'indigo',
    'violet'
]

export function chalkRainbowColor(input: string, color: number): string
{
    //+4 starts with blue not red
    return chalk.keyword(CHALK_RAINBOW_COLORS[Math.abs(color + 4) % CHALK_RAINBOW_COLORS.length])(input)
}

function toStringToListEntry(item: any, indent: number, callback: (itemSuffix: string, toStringPadding: number) => void)
{
    const isItemComplex = isComplexObject(item)
    const extraIndent = isItemComplex ? 4 : 0
    const toStringPadding = isItemComplex ? (indent + extraIndent) : 0
    const itemSuffix = isItemComplex ? `\n` : " "

    callback(itemSuffix, toStringPadding)
}

export function join(items: any[] | Set<any>, separator: string = ", "): string
{
    let text: string

    if(items instanceof Set)
    {
        text = joinSet(items, separator)
    }
    else
    {
        text = items.join(separator)
    }

    return text
}

export function joinSet<T>(set: Set<T>, joinText: string = ", ", itemToString: (item: T) => string = objectToString): string
{
    let output = ""

    if(set.size <= 0)
    {
        return output
    }

    let first = true

    for(const item of set)
    {
        if(!first)
        {
            output += joinText
        }

        output += itemToString(item)
        first = false
    }

    return output
}

export function isTypingChar(char: string): boolean
{
    if (char.length != 1)
    {
        return false
    }

    if(char.match(/[\d\w]/) == null)
    {
        return false
    }

    return true
}

export async function repeatForAsyncS(durationS: number, intervalS: number, stopIfTrue: () => boolean)
{
    return repeatForAsyncMs(durationS * 1000, intervalS * 1000, stopIfTrue)
}

export async function repeatForAsyncMs(durationMs: number, intervalMs: number, stopIfTrue: () => boolean)
{
    const endTime = Date.now() + durationMs

    return whileFalseAsyncMs(intervalMs, () =>
    {
        if(Date.now() <= endTime || stopIfTrue())
        {
            return false
        }

        return true
    })
}

export async function whileFalseAsyncS(intervalS: number, stopIfTrue: () => boolean)
{
    return whileFalseAsyncMs(intervalS * 1000, stopIfTrue)
}

export async function whileFalseAsyncMs(intervalMs: number, stopIfTrue: () => boolean)
{
    return new Promise(async (resolve, reject) =>
    {
        let task: number = undefined!
        
        task = setInterval(() =>
        {
            if(stopIfTrue())
            {
                clearInterval(task)
                resolve(true)
            }
        }, intervalMs);
    })
}

