export function stringify(obj: any): string
{
    return JSON.stringify(obj, null, "\t").replace(/: ([{\[])\n([\t]*)\t/g, ":\n$2$1\n$2\t")
}

export function wrapIndex(thisIndex: number, offset: number, length: number): number
{
    return ((thisIndex + offset) % length + length) % length
}

export function getWrapped<T>(array: T[], index: number, offset: number = 0): T
{
    return array[wrapIndex(index, offset, array.length)]
}

export function getRectCenter(rect: DOMRect): Pos
{
    return {
        x: rect.left + rect.width / 2,
        y: rect.top + rect.height / 2,
    }
}

export function getSimpleDirectionFromPosToPos(origin: Pos, target: Pos): Direction2D4
{
    const xDiff = target.x - origin.x
    const yDiff = target.y - origin.y

    const absXDiff = Math.abs(xDiff)
    const absYDiff = Math.abs(yDiff)

    const isVertical = absXDiff < absYDiff

    const diff = isVertical ? yDiff : xDiff

    if(0 < diff)
    {
        return isVertical ? Direction2D4.Down : Direction2D4.Right
    }
    else
    {
        return isVertical ? Direction2D4.Up : Direction2D4.Left
    }
}

export function getSimpleVerticalDirectionFromPosToPos(origin: Pos, target: Pos): Direction2D4
{
    const diff = target.y - origin.y

    if(0 < diff)
    {
        return Direction2D4.Down
    }
    else
    {
        return Direction2D4.Up
    }
}

export function translateRectToWorldRect(rect: DOMRect, theCamera: Camera = get(currentCamera))
{
    rect.x -= theCamera.x
    rect.y -= theCamera.y
}

export function translatePosToWorldPos(pos: Pos, theCamera: Camera = get(currentCamera))
{
    pos.x -= theCamera.x
    pos.y -= theCamera.y
}

export function distanceSqRaw(x1: number, y1: number, x2: number, y2: number): number
{
    const xDiff = x2 - x1
    const yDiff = y2 - y1

    return xDiff * xDiff + yDiff * yDiff
}

export function distanceSq(pos1: Pos, pos2: Pos): number
{
    const xDiff = pos2.x - pos1.x
    const yDiff = pos2.y - pos1.y

    return xDiff * xDiff + yDiff * yDiff
}

export function distance(pos1: Pos, pos2: Pos): number
{
    return Math.sqrt(distanceSq(pos1, pos2))
}

export function errorToString(error: any): string
{
    if(error instanceof Error)
    {
        return error.message
    }
    else
    {
        return String(error)
    }
}

//#region random
export function randomRare(rareChance: number, minCommon: number, maxCommon: number, minRare: number, maxRare: number): number
{
    if(randomBoolean(rareChance))
    {
        return random(minRare, maxRare)
    }

    return random(minCommon, maxCommon)
}

export function randomRareInt(rareChance: number, minCommon: number, maxCommon: number, minRare: number, maxRare: number): number
{
    if(randomBoolean(rareChance))
    {
        return randomInt(minRare, maxRare)
    }

    return randomInt(minCommon, maxCommon)
}

export async function randomTimes(min: number, max: number, recursiveChance: number, action: () => void | Promise<void>)
{
    const times = randomInt(min, max)
    for(let i = 0; i < times; ++i)
    {
        await action()
    }
    while(randomBoolean(recursiveChance))
    {
        await action()
    }
}

export function randomInt(min: number, max: number): number
{
	if (min > max)
	{
		const temp = min
		min = max
		max = temp
	}
	return(Math.floor(Math.random() * (Math.floor(max) - Math.floor(min) + 1) + Math.floor(min)))
}

export function random(min: number, max: number): number
{
	if (min > max)
	{
		const temp = min
		min = max
		max = temp
	}
	return(Math.random() * (max - min) + min)
}

export function randomBoolean(chance: number = 0.5): boolean
{
    return Math.random() < chance
}

export function randomFromArray<T>(array: T[]): T
{
    return array[randomInt(0, array.length-1)]
}

export function randomFromArrayButNot<T>(array: T[], not: T): T
{
    while(true)
    {
        const item = array[randomInt(0, array.length-1)]

        if(item != not)
        {
            return item
        }
    }
}
