export function rgbToHsl(r: number, g: number, b: number)
{
    r /= 255
    g /= 255
    b /= 255

    const max = Math.max(r, g, b)
    const min = Math.min(r, g, b)
    const d = max - min

    let h = 0

    if (d !== 0)
    {
        if (max === r) h = ((g - b) / d) % 6
        else if (max === g) h = (b - r) / d + 2
        else h = (r - g) / d + 4

        h *= 60
        if (h < 0) h += 360
    }

    const l = (max + min) / 2
    const s = d === 0 ? 0 : d / (1 - Math.abs(2 * l - 1))

    return { h, s, l }
}

export function hslToRgb(h: number, s: number, l: number)
{
    const c = (1 - Math.abs(2 * l - 1)) * s
    const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
    const m = l - c / 2

    let r = 0, g = 0, b = 0

    if      (h <  60) { r = c; g = x; b = 0 }
    else if (h < 120) { r = x; g = c; b = 0 }
    else if (h < 180) { r = 0; g = c; b = x }
    else if (h < 240) { r = 0; g = x; b = c }
    else if (h < 300) { r = x; g = 0; b = c }
    else              { r = c; g = 0; b = x }

    return {
        r: Math.round((r + m) * 255),
        g: Math.round((g + m) * 255),
        b: Math.round((b + m) * 255)
    }
}

export function insertText(input: HTMLInputElement, text: string)
{
    const start = input.selectionStart ?? 0
    const end = input.selectionEnd ?? 0

    input.value =
        input.value.slice(0, start) +
        text +
        input.value.slice(end)

    const caret = start + text.length

    input.selectionStart = caret
    input.selectionEnd = caret

    input.focus()

    // force browser to reveal caret
    input.scrollLeft = input.scrollWidth

    input.dispatchEvent(new Event("input", { bubbles: true }))
}

export function updateTextBoxSize(editingBox: HTMLElement)
{
    const newValue = Math.min(parseInt(editingBox.style.maxWidth), editingBox.scrollWidth)
    editingBox.style.width = `${newValue}px`
}

export function limitWithinRange(value: number, min: number, max: number): number
{
    return Math.min(Math.max(value, min), max)
}

export function interpolate(start: number, end: number, ratio: number): number
{
    return start + (end - start) * ratio
}

export function getAbsDifference(a: number, b: number): number
{
    return Math.abs(a - b)
}

export function isWithinRange(value: number, min: number, max: number): boolean
{
    return min <= value && value <= max
}

export function isWithinRangeOf(value: number, target: number, range: number): boolean
{
    return isWithinRange(value, target - range, target + range)
}

export function getMouseWheelEventDirection(e: WheelEvent): Direction2D4
{
    // log(`deltaX: ${e.deltaX}, deltaY: ${e.deltaY}`)

    if(Math.abs(e.deltaX) < Math.abs(e.deltaY))
    {
        if(e.deltaY < 0)
        {
            return Direction2D4.Up
        }
        else
        {
            return Direction2D4.Down
        }
    }
    else
    {
        if(e.deltaX < 0)
        {
            return Direction2D4.Left
        }
        else
        {
            return Direction2D4.Right
        }
    }
}

export function getOrCreateMap<K, V>(map: Map<K, V>, key: K, createValue: () => V): V
{
    let value = map.get(key)

    if(value == null)
    {
        value = createValue()
        map.set(key, value)
    }

    return value
}

export function incrementMapSoft<K, V>(map: Map<K, number>, key: K, incrementBy: number = 1): number
{
    let value = map.get(key)

    if(value == null)
    {
        map.set(key, incrementBy)
        value = incrementBy
    }

    return incrementBy
}

export function incrementRecordSoft<K extends string | number | symbol, V>(map: Record<K, number>, key: K, incrementBy: number = 1): number
{
    let value = map[key]

    if(value == null)
    {
        map[key] = incrementBy
        value = incrementBy
    }

    return incrementBy
}

export function scaleRect(rect: DOMRect, scale: number)
{
    rect.x *= scale
    rect.y *= scale
    rect.width *= scale
    rect.height *= scale
}

export function unfocusTabIndex()
{
    setTabIndexFocusedNode()
    ;(document.activeElement as HTMLElement | null)?.blur()
}

export function addAllFromTo<T, C extends Array<T> | Set<T>>(items: Iterable<T>, collection: C)
{
    for (const item of items)
    {
        if (collection instanceof Array)
        {
            collection.push(item)
        }
        else if (collection instanceof Set)
        {
            collection.add(item)
        }
    }
}

export function softToFixed(num: number, maxDecimals: number = 2): string
{
    if (!isFinite(num))
    {
        return String(num)
    }
    const factor = Math.pow(10, maxDecimals)
    const rounded = Math.round(num * factor) / factor
    return rounded.toString()
}

export function toStamp(toStamp: number): string
{
    if(isNaN(toStamp) || toStamp == Infinity || toStamp == -Infinity)
    {
        toStamp = 0
    }

    let stamped: string = ''
    toStamp = Math.floor(toStamp)
    let negative = false
    if(toStamp < 0)
    {
        toStamp = -toStamp
        negative = true
    }
    if (Math.floor(toStamp/3600) >= 24)
    {
        if (Math.floor(toStamp/3600) < 48)
            stamped += `[${Math.floor(toStamp/86400)}] day, `
        else
            stamped += `[${Math.floor(toStamp/86400)}] days, `
    }
    stamped += 
        '[' +
            Math.floor(toStamp % 86400 / 3600) + '\:' + 
            (Math.floor(toStamp % 3600 / 60) > 9 ? Math.floor(toStamp % 3600 / 60) : ('0' + Math.floor(toStamp % 3600 / 60))) + '\:' +
            (Math.floor(toStamp % 60) > 9 ? toStamp % 60 : '0' + toStamp % 60) +
        ']'
    if(negative)
        return `-${stamped}`
    else
        return stamped
}

export function normalizeVec2(pos: Pos): Pos
{
    const length = Math.sqrt(pos.x * pos.x + pos.y * pos.y)
    
    if(length == 0)
    {
        return { x: 0, y: 0 }
    }

    return {
        x: pos.x / length,
        y: pos.y / length,
    }
}

export function xmur3(str: string)
{
	let h = 1779033703 ^ str.length

	for(let i = 0; i < str.length; i++)
	{
		h = Math.imul(h ^ str.charCodeAt(i), 3432918353)
		h = h << 13 | h >>> 19
	}

	return function()
	{
		h = Math.imul(h ^ h >>> 16, 2246822507)
		h = Math.imul(h ^ h >>> 13, 3266489909)

		return (h ^= h >>> 16) >>> 0
	}
}

export function mulberry32String(seed: string, asInt: boolean = true)
{
    return mulberry32(xmur3(seed)(), asInt)
}

export function mulberry32(seed: number, asInt: boolean = true)
{
	return function()
	{
		let t = seed += 0x6D2B79F5

		t = Math.imul(t ^ t >>> 15, t | 1)
		t ^= t + Math.imul(t ^ t >>> 7, t | 61)

		return ((t ^ t >>> 14) >>> 0) / (asInt ? 1 : 4294967296)
	}
}

export function getLast<T>(array: T[]): T
{
    return array[array.length - 1]
}
export function getLastChar(text: string): string
{
    return text.charAt(text.length - 1)
}



export function addAllFromToWritable<V, C extends Array<V>>(writable: Writable<C>, items: C | V)
{
    writable.update(current =>
    {
        if(Array.isArray(items))
        {
            addAllFromTo(items, current)
        }
        else
        {
            current.push(items)
        }

        return current
    })
}

export function getLastFromWritable<V>(writable: Writable<V[]>): V
{
    const items = get(writable)

    return getLast(items)
}

export function softArrayGet<T>(array: T[], index: number): T
{
    if(index < 0 || index >= array.length)
    {
        return null!
    }

    return array[index]
}

export async function waitMs(ms: number)
{
    return new Promise(resolve => setTimeout(resolve, ms))
}

export async function waitS(s: number)
{
    return new Promise(resolve => setTimeout(resolve, s * 1000))
}

export function sIfNot1(count: number): string
{
    return count == 1 ? "" : "s"
}

export function getOrDefaultArray<T>(array: T[], index: number, defaultValue: T = null!): T
{
    if(index < 0 || index >= array.length)
    {
        return defaultValue
    }

    return array[index]
}

export const metricPrefixes = ["", "k", "m", "g", "t", "p", "e", "z", "y"]

export function formatSize(bytes: number)
{
    if(isNaN(bytes) || bytes == Infinity || bytes == -Infinity)
    {
        return ""
    }

    let tier = 0

    while(1000 < bytes)
    {
        bytes /= 1000
        ++tier
    }

    let prefix = getOrDefaultArray(metricPrefixes, tier, "CIB (Cubic Infinity Bytes)")
    
    return `${softToFixed(bytes)}${prefix}b`
}

export function formatDate(date: Date): string
{
    //Format: HH:SS:MM DD/MM/YYYY

    const hours = date.getHours()
    const minutes = date.getMinutes()
    const seconds = date.getSeconds()

    const day = date.getDate()
    const month = date.getMonth() + 1
    const year = date.getFullYear()

    return `${hours > 9 ? hours : "0" + hours}:${minutes > 9 ? minutes : "0" + minutes}:${seconds > 9 ? seconds : "0" + seconds} ${day > 9 ? day : "0" + day}/${month > 9 ? month : "0" + month}/${year}`   
}

export function isMimeTypeFolder(mimetype: string): boolean
{
    return mimetype === MIMETYPE_GOOGLE_DRIVE_FOLDER
}

export function isAppFileFolder(file: AppFile): boolean
{
    return isMimeTypeFolder(file.mimeType)
}

